import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, LogIn, Play, Download,
  RefreshCw, ListPlus, Paperclip, XCircle, Gift, Calendar, Crown, Star, KeyRound, Building2, Mail,
  PieChart, LineChart
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

/* ============================================================================
   CONSTANTS & PRICING
   ============================================================================ */
const SUBSCRIPTION_PACKAGES = [
  { id: 'sub_1', name: 'Basic Plan', price: 49, credits: 2000, features: ['2,000 Credits per month', 'Basic Support', 'Valid for 30 Days'], icon: Star, popular: false },
  { id: 'sub_2', name: 'Pro Plan', price: 99, credits: 5000, features: ['5,000 Credits per month', 'Priority Support', 'Valid for 30 Days'], icon: Crown, popular: true },
  { id: 'sub_3', name: 'Ultimate Plan', price: 179, credits: 10000, features: ['10,000 Credits per month', 'Dedicated Account Manager', 'Valid for 30 Days'], icon: ShieldCheck, popular: false }
];

const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1500, price: 40, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 4000, price: 90, label: 'Pro Reload', icon: Coins, bonus: '+200 Bonus', popular: true },
  { id: 'tu_4', amount: 10000, price: 180, label: 'Enterprise Reload', icon: Database, bonus: '+500 Bonus' }
];

const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://quickchart.io/qr?text=${encodeURIComponent(value)}&size=${size}&margin=1`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

/* ============================================================================
   ADMIN PORTAL
   ============================================================================ */
const AdminPortal = ({ currentUser, onLogout, token }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [allUsers, setAllUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // System Settings State
  const [sysSettings, setSysSettings] = useState({ allowRegistration: true, maintenanceMode: false });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  // Notifications & Modals
  const [notification, setNotification] = useState({ show: false, title: '', message: '', type: 'info' });
  const [manageUserModal, setManageUserModal] = useState({ isOpen: false, user: null, newCredit: 0, newPlan: 'Free Account' });

  const showNotification = (title, message, type = 'info') => {
    setNotification({ show: true, title, message, type });
  };

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/admin/users`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setAllUsers(data);
      }
    } catch (err) { 
      showNotification("Error", "Failed to fetch user data from the server.", "error"); 
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [token]);

  // Dynamic Statistics
  const totalUsers = allUsers.length;
  const totalCredits = allUsers.reduce((sum, user) => sum + (user.kredit || 0), 0);
  const activeSessions = allUsers.filter(user => user.sesi_whatsapp_aktif).length;

  // Search Filter
  const filteredUsers = allUsers.filter(u => 
    u.nama_syarikat?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    u.email?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleUpdateAccountSubmit = async (e) => {
    e.preventDefault();
    try {
      // NOTE: Make sure your backend API '/admin/update-user' accepts 'plan' field now.
      const res = await fetch(`${API_URL}/admin/update-user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify({ 
          userId: manageUserModal.user._id, 
          kredit: parseInt(manageUserModal.newCredit),
          plan: manageUserModal.newPlan
        })
      });
      if (res.ok) {
        showNotification("Success", `Account for ${manageUserModal.user.nama_syarikat} has been updated.`, "success");
        setManageUserModal({ isOpen: false, user: null, newCredit: 0, newPlan: 'Free Account' });
        fetchUsers();
      } else {
        showNotification("Error", "Failed to save account data. Please check backend API.", "error");
      }
    } catch (err) { 
      showNotification("Network Error", "Server could not be reached.", "error"); 
    }
  };

  const handleDeleteUser = async (userId, companyName) => {
    if (!window.confirm(`Are you sure you want to delete the account for ${companyName}? This action cannot be undone.`)) return;
    try {
      const res = await fetch(`${API_URL}/admin/users/${userId}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        showNotification("Deleted", "User account has been deleted successfully.", "success");
        fetchUsers();
      } else {
        showNotification("Error", "Failed to delete the user.", "error");
      }
    } catch (err) {
      showNotification("Network Error", "Server could not be reached.", "error");
    }
  };

  const handleSaveSettings = () => {
    setIsSavingSettings(true);
    // Simulate API Call for saving settings
    setTimeout(() => {
      setIsSavingSettings(false);
      showNotification("Settings Saved", "System configuration updated successfully.", "success");
    }, 1000);
  };

  const openManageModal = (user) => {
    setManageUserModal({ 
      isOpen: true, 
      user: user, 
      newCredit: user.kredit || 0, 
      newPlan: user.plan || 'Free Account' 
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full relative">
      <style>{`
        .hide-scrollbar::-webkit-scrollbar { display: none; }
        .hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      {/* GLOBAL NOTIFICATION MODAL */}
      {notification.show && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white p-8 rounded-[2rem] shadow-2xl max-w-sm w-full text-center border border-slate-100">
            <div className="flex justify-center mb-5">
              {notification.type === 'warning' ? <AlertCircle size={56} className="text-amber-500" /> :
               notification.type === 'error' ? <XCircle size={56} className="text-red-500" /> :
               <CheckCircle2 size={56} className="text-emerald-500" />}
            </div>
            <h3 className="text-xl font-black text-slate-800 mb-2">{notification.title}</h3>
            <p className="text-slate-500 font-medium mb-8 text-sm">{notification.message}</p>
            <button onClick={() => setNotification({ ...notification, show: false })} className="w-full py-3.5 bg-slate-900 text-white rounded-2xl font-black hover:bg-slate-800 transition-colors">Close</button>
          </div>
        </div>
      )}

      {/* MANAGE USER MODAL */}
      {manageUserModal.isOpen && (
        <div className="fixed inset-0 z-[90] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-[2.5rem] shadow-2xl max-w-md w-full border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-6 flex justify-between items-center text-white">
               <div className="flex items-center gap-3">
                 <div className="bg-emerald-500 p-2 rounded-xl text-white"><Settings size={20}/></div>
                 <h3 className="font-black text-lg">Update Account</h3>
               </div>
               <button onClick={() => setManageUserModal({ isOpen: false, user: null, newCredit: 0, newPlan: 'Free Account' })} className="text-slate-400 hover:text-white"><X size={24}/></button>
            </div>

            <form onSubmit={handleUpdateAccountSubmit} className="p-8 space-y-6">
                <div className="space-y-1 mb-4">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Company / Customer Name</p>
                  <p className="font-bold text-lg text-slate-800">{manageUserModal.user.nama_syarikat}</p>
                  <p className="text-xs text-slate-500 font-medium">{manageUserModal.user.email}</p>
                </div>

